/* TerraHype natural-world records for the Library 'Wonders' tab. */
window.__SEA_MARVELS__ = [{"title": "The tallest living thing on Earth", "fact": "A coast redwood in California named Hyperion stands about 116 m tall - taller than a 35-story building. Redwoods are the tallest trees known to exist.", "src": "usfs"}, {"title": "The largest single living thing by volume", "fact": "A giant sequoia called General Sherman holds more wood than any other single tree, weighing an estimated 1,900 tonnes - yet it grew from a seed smaller than an oat flake.", "src": "nps"}, {"title": "Among the oldest living things", "fact": "Great Basin bristlecone pines high in the western mountains can live more than 4,800 years, making some older than the pyramids of Egypt.", "src": "usfs"}, {"title": "Possibly the largest organism of all", "fact": "A single honey fungus in Oregon spreads its underground threads across roughly 9 square kilometers and may be thousands of years old - by area, perhaps the biggest organism on Earth.", "src": "usfs"}, {"title": "The fastest animal on the planet", "fact": "In a hunting dive the peregrine falcon exceeds 320 km/h, faster than a race car, making it the fastest animal known.", "src": "cornell"}, {"title": "The fastest land animal in North America", "fact": "The pronghorn can sprint at over 80 km/h and hold a fast pace for miles - speed thought to have evolved to outrun long-extinct American cheetahs.", "src": "usfws"}, {"title": "One of nature's greatest journeys", "fact": "Monarch butterflies travel thousands of kilometers from as far as Canada to the same small patch of Mexican forest each year, a trip no single butterfly completes both ways.", "src": "si"}, {"title": "The longest cave on Earth", "fact": "Mammoth Cave in Kentucky has more than 686 km of mapped passages - by far the longest known cave system in the world, and still growing as explorers map more.", "src": "nps"}, {"title": "North America's highest peak", "fact": "Denali in Alaska rises about 6,190 m above sea level, and measured from its base it is one of the tallest mountains on land anywhere.", "src": "usgs"}, {"title": "Some of the oldest rock on Earth", "fact": "Rocks in northern Canada have been dated to around 4 billion years old - nearly as old as the planet itself - preserving a record from Earth's distant youth.", "src": "usgs"}, {"title": "Two billion years of history in one canyon", "fact": "The walls of the Grand Canyon expose rock layers spanning nearly 2 billion years, letting visitors look back across an immense stretch of Earth's past in a single view.", "src": "nps"}, {"title": "A dam you can see from space", "fact": "Beavers in northern Canada built a dam over 850 m long - so large it can be spotted in satellite images - showing how powerfully these animals reshape the land.", "src": "nwf"}];
